// Goal state store — AB-5.
//
// Persists per-chat /goal state so it survives bridge restarts and
// idle-session drops. Schema documented in docs/ab-token-protocol.md §6.2.
//
// State machine:
//
//   (no file) --/goal text-->           active
//   active    --GOAL_DONE-->            done
//   active    --budget reached-->       paused
//   active    --/goal pause-->          paused
//   active    --/goal clear-->          cleared
//   paused    --/goal resume-->         active (turns_used reset to 0)
//   paused    --/goal clear-->          cleared
//   done      --/goal clear-->          cleared
//   done      --/goal <new text>-->     active (new objective)
//   cleared   --/goal <new text>-->     active (new objective)
//
// Rejection rules:
//   - set() while status='active' or 'paused' → thrown error; caller
//     must /stop or /goal clear first.
//   - pause/resume/clear/markDone on missing file → thrown error.
//   - incrementTurn on non-active goal → thrown error.
//
// File layout:
//   ${MEMORY_DIR}/goal-state/<chat_id>.json
//
// Concurrency: serialized via atomicJson per file path — each chat's
// goal state file has its own independent chain.
import path from "node:path";
import { atomicWriteJson, readJsonOrDefault, updateJson, } from "./atomicJson.js";
export const DEFAULT_MAX_TURNS = 5;
/** Maximum number of reflection retries when a goal exhausts budget without GOAL_DONE. */
export const GOAL_REFLECTION_MAX = 3;
// Guardrail constants for <<RESTART>> token (C3, 2026-05-02). Hard-coded
// on purpose — the user chose "default, no env var override; change here
// if it turns out to be wrong." See docs/ab-token-protocol.md §RESTART.
/** Minimum gap between two successful RESTARTs on the same goal. */
export const GOAL_RESTART_COOLDOWN_MS = 5 * 60 * 1000;
/** Maximum number of RESTARTs a single goal can fire. */

